def process_graph(graph_data):
    # Create a copy of the graph
    graph_copy = graph_data.copy()

    # Find the EK_CONTROL_DOMAIN node with name 'ju1.s4.dom'
    control_domain_id = None
    for node_id, node_attr in graph_copy.nodes(data=True):
        if node_attr.get('name') == 'ju1.s4.dom' and 'EK_CONTROL_DOMAIN' in node_attr.get('type', []):
            control_domain_id = node_id
            break

    # If the control domain node is not found, return empty result
    if control_domain_id is None:
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Get all direct child nodes of the control domain
    child_ids = []
    for _, child_id, edge_data in graph_copy.out_edges(control_domain_id, data=True):
        edge_type = edge_data.get('type')
        if edge_type in ['RK_CONTAINS', 'RK_CONTROL']:
            child_ids.append(child_id)

    # Calculate total capacity for each child node
    results = []
    for child_id in child_ids:
        child_name = graph_copy.nodes[child_id].get('name', str(child_id))
        total_capacity = 0

        # Use stack for DFS traversal to find all PORT nodes under this child
        stack = [child_id]
        visited = set()

        while stack:
            current_id = stack.pop()

            if current_id in visited:
                continue
            visited.add(current_id)

            current_attr = graph_copy.nodes[current_id]

            # If it's a PORT node, add its capacity
            if 'EK_PORT' in current_attr.get('type', []):
                total_capacity += current_attr.get('physical_capacity_bps', 0)

            # Add all contained child nodes to stack
            for _, next_id, edge_data in graph_copy.out_edges(current_id, data=True):
                if edge_data.get('type') == 'RK_CONTAINS':
                    stack.append(next_id)

        results.append((child_name, total_capacity))

    # Sort results by capacity in descending order
    results.sort(key=lambda x: x[1], reverse=True)

    # Format and return the result
    return_object = {
        'type': 'list',
        'data': results,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object

