    # Create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Threshold: 10 Tbps in bps
    THRESHOLD_BPS = 10 * 10**12

    # Find all CHASSIS nodes
    chassis_list = []
    for node_id, attrs in graph_copy.nodes(data=True):
        if 'EK_CHASSIS' in attrs.get('type', []):
            chassis_list.append((node_id, attrs))

    # Prepare results table with header
    table_data = [['Chassis Name', 'Total Capacity (Tbps)']]

    # Calculate capacity for each chassis
    for chassis_id, chassis_attrs in chassis_list:
        total_bps = 0

        # Find PACKET_SWITCH nodes contained by this CHASSIS
        for ps_id in graph_copy.successors(chassis_id):
            edge_data = graph_copy.get_edge_data(chassis_id, ps_id)
            if edge_data and edge_data.get('type') == 'RK_CONTAINS':
                ps_attrs = graph_copy.nodes[ps_id]
                if 'EK_PACKET_SWITCH' in ps_attrs.get('type', []):

                    # Find PORT nodes contained by this PACKET_SWITCH
                    for port_id in graph_copy.successors(ps_id):
                        port_edge_data = graph_copy.get_edge_data(ps_id, port_id)
                        if port_edge_data and port_edge_data.get('type') == 'RK_CONTAINS':
                            port_attrs = graph_copy.nodes[port_id]
                            if 'EK_PORT' in port_attrs.get('type', []):
                                total_bps += port_attrs.get('physical_capacity_bps', 0)

        # Check if capacity is below threshold
        if total_bps < THRESHOLD_BPS:
            chassis_name = chassis_attrs.get('name', chassis_id)
            capacity_tbps = total_bps / (10**12)
            table_data.append([chassis_name, capacity_tbps])

    # Generate graph JSON for the updated graph
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    # Return the object in required format
    return {
        'type': 'table',
        'data': table_data,
        'updated_graph': graph_json
    }

